import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from './hooks/useAuth';

/**
 * Authentication page. Since Firebase has been removed, this page
 * prompts the user for their name and stores it in localStorage.
 * Once a name is provided, the user is considered "logged in" and
 * redirected to the main application. If the user is already
 * authenticated (a valid auth object exists in localStorage), they
 * will be redirected immediately without seeing this form.
 */
export const Auth = () => {
  const [nameInput, setNameInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();
  const { isAuth } = useAuth();

  // Redirect authenticated users to the home page
  useEffect(() => {
    if (isAuth) {
      navigate('/app');
    }
  }, [isAuth, navigate]);

  const handleLogin = () => {
    const trimmedName = nameInput.trim();
    setError('');
    if (!trimmedName) {
      setError('Please enter your name');
      return;
    }
    setIsLoading(true);
    setTimeout(() => {
      const authInfo = {
        name: trimmedName,
        userID: Date.now().toString(),
        photo: null,
        isAuth: true,
      };
      localStorage.setItem('auth', JSON.stringify(authInfo));
      navigate('/app');
    }, 300);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && nameInput.trim()) {
      handleLogin();
    }
  };

  return (
    <div className="relative min-h-screen flex items-center justify-center px-4 overflow-hidden">
      {/* Animated background gradients */}
      <div className="absolute inset-0 bg-gradient-to-br from-blue-600 via-purple-600 to-pink-500 animate-pulse"></div>
      <div className="absolute inset-0 bg-gradient-to-tl from-blue-500 via-indigo-600 to-purple-600 opacity-80"></div>

      {/* Decorative animated shapes */}
      <div className="absolute top-20 left-10 w-72 h-72 bg-blue-400 rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob"></div>
      <div className="absolute top-40 right-10 w-72 h-72 bg-pink-400 rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob animation-delay-2s"></div>
      <div className="absolute -bottom-8 left-20 w-72 h-72 bg-purple-400 rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob animation-delay-4s"></div>

      {/* Main card container */}
      <div className="relative z-10 w-full max-w-md">
        <div className="backdrop-blur-xl bg-white/95 rounded-3xl shadow-2xl p-8 sm:p-10 border border-white/20">
          {/* Logo and header */}
          <div className="text-center mb-8">
            <div className="inline-block mb-4 p-4 bg-gradient-to-br from-blue-500 to-purple-600 rounded-2xl transform hover:scale-110 transition-transform duration-300">
              <span className="text-4xl">💰</span>
            </div>
            <h1 className="text-4xl sm:text-5xl font-bold bg-gradient-to-r from-blue-600 via-purple-600 to-pink-600 bg-clip-text text-transparent mb-2 animate-fade-in">
              Budget Buddy
            </h1>
            <p className="text-gray-600 text-sm sm:text-base font-medium">
              Smart spending, better decisions
            </p>
          </div>

          {/* Features list */}
          <div className="mb-8 space-y-3">
            <div className="flex items-center text-gray-700 text-sm">
              <span className="text-xl mr-3">📊</span>
              <span>Track your expenses effortlessly</span>
            </div>
            <div className="flex items-center text-gray-700 text-sm">
              <span className="text-xl mr-3">💡</span>
              <span>Get insights on your spending</span>
            </div>
            <div className="flex items-center text-gray-700 text-sm">
              <span className="text-xl mr-3">🎯</span>
              <span>Achieve your financial goals</span>
            </div>
          </div>

          {/* Input field */}
          <div className="mb-6">
            <label className="block text-sm font-semibold text-gray-700 mb-3">
              What's your name?
            </label>
            <div className="relative group">
              <input
                type="text"
                placeholder="Enter your name"
                value={nameInput}
                onChange={(e) => {
                  setNameInput(e.target.value);
                  setError('');
                }}
                onKeyPress={handleKeyPress}
                disabled={isLoading}
                className="w-full px-5 py-4 rounded-xl border-2 border-gray-200 focus:border-purple-500 focus:outline-none transition-all duration-300 bg-gray-50 focus:bg-white placeholder-gray-400 text-gray-800 disabled:opacity-60 disabled:cursor-not-allowed shadow-sm focus:shadow-lg focus:shadow-purple-200"
              />
              <span className="absolute right-4 top-1/2 transform -translate-y-1/2 text-2xl">✨</span>
            </div>
            {error && (
              <p className="text-red-500 text-sm mt-2 font-medium animate-pulse">
                ⚠️ {error}
              </p>
            )}
          </div>

          {/* Login button */}
          <button
            onClick={handleLogin}
            disabled={isLoading || !nameInput.trim()}
            className="w-full bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 disabled:from-gray-400 disabled:to-gray-500 text-white font-bold py-4 px-6 rounded-xl transition-all duration-300 transform hover:scale-105 hover:shadow-lg active:scale-95 disabled:opacity-60 disabled:cursor-not-allowed shadow-lg hover:shadow-purple-500/50 flex items-center justify-center gap-2 text-lg"
          >
            {isLoading ? (
              <>
                <span className="animate-spin">⏳</span>
                Getting started...
              </>
            ) : (
              <>
                Let's Go
                <span className="text-xl">🚀</span>
              </>
            )}
          </button>

          {/* Divider */}
          <div className="my-6 flex items-center gap-4">
            <div className="flex-1 h-px bg-gradient-to-r from-transparent to-gray-300"></div>
            <span className="text-gray-400 text-xs font-semibold">NO LOGIN NEEDED</span>
            <div className="flex-1 h-px bg-gradient-to-l from-transparent to-gray-300"></div>
          </div>

          {/* Footer text */}
          <p className="text-center text-gray-600 text-xs">
            Your data is stored locally • No account required • 100% private
          </p>
        </div>

        {/* Bottom decoration */}
        <div className="mt-8 text-center text-white/80 text-sm">
          <p>Ready to take control of your finances? ✨</p>
        </div>
      </div>

      {/* CSS animations */}
      <style>{`
        @keyframes blob {
          0%, 100% {
            transform: translate(0, 0) scale(1);
          }
          33% {
            transform: translate(30px, -50px) scale(1.1);
          }
          66% {
            transform: translate(-20px, 20px) scale(0.9);
          }
        }

        @keyframes fade-in {
          from {
            opacity: 0;
            transform: translateY(-10px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        .animate-blob {
          animation: blob 7s infinite;
        }

        .animation-delay-2s {
          animation-delay: 2s;
        }

        .animation-delay-4s {
          animation-delay: 4s;
        }

        .animate-fade-in {
          animation: fade-in 0.8s ease-out;
        }
      `}</style>
    </div>
  );
};
